  ('elementary-0a2fc18c-moex-00563', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '假設一消費者認為蘋果與橘子沒有任何差別，則下列敘述何者錯誤？', '["蘋果與橘子為完全替代", "無異曲線為一直線", "邊際替代率遞減法則成立", "若兩者價格不同，則消費者只會購買價格較低者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "64309f0e4e1f", "answer_pdf_sha1": "e301272da8a3", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00564', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '小白為了開一家糖果店，放棄了年薪50萬元的高中老師教職。另外，小白從年利率3%的定期存款戶頭 中提出了20萬元，也向銀行借了10萬元，年利率為3%。小白糖果店今年的所有材料費為25萬元，且 總收益為60萬元。下列何者正確？', '["小白今年的會計利潤為34.1萬元，經濟利潤為35萬元", "小白今年的會計利潤為34.1萬元，經濟利潤為15.9萬元", "小白今年的會計利潤為34.7萬元，經濟利潤為15.9萬元", "小白今年的會計利潤為34.7萬元，經濟利潤為34.1萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "64309f0e4e1f", "answer_pdf_sha1": "e301272da8a3", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00565', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '假設某農夫僱用2名工人時，能生產出300公斤的玉米，僱用3名工人時，能生產出440公斤的玉米。 下列何者可以顯示某農夫僱用的工人會有勞動邊際產量遞減的情況？', '["僱用4名工人時，能生產出560公斤的玉米", "僱用4名工人時，能生產出580公斤的玉米", "僱用4名工人時，能生產出600公斤的玉米", "僱用4名工人時，能生產出700公斤的玉米"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "64309f0e4e1f", "answer_pdf_sha1": "e301272da8a3", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00566', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '當在某個產量區間，廠商的平均總成本都大於邊際成本。則下列敘述何者正確？', '["邊際成本隨產量增加而遞減", "邊際成本隨產量增加而遞增", "平均總成本隨產量增加而遞增", "平均總成本隨產量增加而遞減"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "64309f0e4e1f", "answer_pdf_sha1": "e301272da8a3", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00567', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '下列訂價模式中，何者不算是三級價格歧視（pricediscrimination）？', '["相同的一杯飲料，男性顧客付出的價格高於女性顧客付出的價格", "同一所大學的學生，男性學生付出的學費高於女性學生付出的學費", "相同保額與年齡的壽險保單，男性保戶付出的保費高於女性保戶付出的保費", "相同的一本書，男性顧客付出的價格高於女性顧客付出的價格"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "64309f0e4e1f", "answer_pdf_sha1": "e301272da8a3", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00568', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '下列有關完全競爭市場的短期市場供給曲線敘述，何者錯誤？', '["不可能是負斜率", "短期市場供給曲線為所有個別廠商短期供給曲線的垂直加總", "短期市場供給曲線的高度反映出此市場中廠商們的邊際成本", "個別廠商追求利潤極大化是推導該曲線過程中的重要假設之一"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "64309f0e4e1f", "answer_pdf_sha1": "e301272da8a3", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00569', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '下列有關獨占性競爭市場的長期或是短期均衡的敘述，何者錯誤？', '["個別廠商在短期均衡之下，其利潤為零", "個別廠商在長期均衡之下，其利潤為零", "個別廠商在長期均衡之下，其利潤極大化的一階條件為邊際收入等於邊際成本", "個別廠商在短期均衡之下，其利潤極大化的一階條件為邊際收入等於邊際成本"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "64309f0e4e1f", "answer_pdf_sha1": "e301272da8a3", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00570', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '假設一個獨占廠商面對負斜率的需求曲線。當此獨占廠商增加其產量時，其平均收益：', '["增加，且邊際收益也增加", "維持不變，且邊際收益也不變", "增加，且邊際收益遞減", "遞減，且邊際收益也遞減"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "64309f0e4e1f", "answer_pdf_sha1": "e301272da8a3", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00571', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '關於貧窮問題的敘述，下列何者錯誤？', '["解決社會貧窮問題是各國政府存在的重要功能之一", "一個經濟社會的貧窮率指的是家庭所得低於貧窮水準的人口比率", "臺灣各縣市設定有最低生活費之標準，作為人民落入貧窮的判斷標準", "因臺灣最低生活費標準未隨物價每年調整，故造成貧窮率逐年提高"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "64309f0e4e1f", "answer_pdf_sha1": "e301272da8a3", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00572', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-2b7ba743', 'sub-elementary-0a2fc18c-04', NULL, 'single_choice', '當政府補助廠商聘用大專應屆畢業生的薪資時，對大專應屆畢業生勞動市場供需最直接的影響會是下列 何者？', '["勞動供給增加", "勞動供給量增加", "勞動需求增加", "勞動需求量增加"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "64309f0e4e1f", "answer_pdf_sha1": "e301272da8a3", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0506", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL)
